// Normalize & Hash Articles
// This Code node processes all merged RSS feed items:
//   1. Extracts title, url, publication date, and content snippet
//   2. Strips HTML tags from content
//   3. Truncates content to 500 characters
//   4. Computes SHA256 hash of the URL for deduplication
//   5. Adds metadata fields (category, processed flag, collected_at)
//
// Error handling: Items missing a URL are skipped with a warning logged.

const crypto = require('crypto');

const results = [];
const now = new Date().toISOString();

for (const item of $input.all()) {
  try {
    const data = item.json;

    // Extract URL - RSS feeds use various field names
    const url = data.link || data.url || data.guid || '';
    if (!url || url.trim() === '') {
      console.warn('Skipping item with no URL:', JSON.stringify(data).substring(0, 200));
      continue;
    }

    // Extract title
    const title = (data.title || 'Untitled').trim();

    // Extract and parse publication date
    let pubDate = data.pubDate || data.isoDate || data.date || data['dc:date'] || now;
    try {
      pubDate = new Date(pubDate).toISOString();
    } catch (e) {
      pubDate = now;
    }

    // Extract content and strip HTML
    let rawContent = data.content || data['content:encoded'] || data.contentSnippet || data.description || data.summary || '';

    // Strip HTML tags
    let contentSnippet = rawContent
      .replace(/<[^>]*>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/\s+/g, ' ')
      .trim();

    // Truncate to 500 characters
    if (contentSnippet.length > 500) {
      contentSnippet = contentSnippet.substring(0, 497) + '...';
    }

    // Compute SHA256 hash of the URL for deduplication
    const hash = crypto.createHash('sha256').update(url.trim()).digest('hex');

    results.push({
      json: {
        hash: hash,
        title: title,
        url: url.trim(),
        date: pubDate,
        content_snippet: contentSnippet,
        category: 'Uncategorized',
        processed: 'false',
        collected_at: now
      }
    });
  } catch (err) {
    console.error('Error processing RSS item:', err.message);
    // Continue processing other items
  }
}

// If no items were processed, return an empty marker to avoid workflow errors
if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No new articles found in this run' } }];
}

return results;

// Filter Duplicates
// Compares new article hashes against existing hashes from Google Sheets.
// Only articles with hashes NOT found in the sheet will pass through.
//
// This node receives items from two upstream paths that have been merged:
//   - Normalized articles (with hash, title, url, date, content_snippet, etc.)
//   - Existing hash rows from Google Sheets (with just a 'hash' field)
//
// We differentiate them by checking for the presence of 'title' and 'url'.

const allItems = $input.all();

// Separate: Sheets items typically have only 'hash' (or 'hash' and row_number),
// while our normalized articles have 'hash', 'title', 'url', etc.
const existingHashes = new Set();
const newArticles = [];

for (const item of allItems) {
  const data = item.json;

  // If item has 'title' and 'url' and 'content_snippet', it's a new article
  if (data.title && data.url && data.content_snippet !== undefined) {
    newArticles.push(item);
  } else if (data.hash) {
    // It's from Google Sheets - just a hash
    existingHashes.add(data.hash);
  }
}

// Filter out duplicates
const uniqueArticles = newArticles.filter(item => {
  return !existingHashes.has(item.json.hash);
});

console.log(`Dedup stats: ${newArticles.length} incoming articles, ${existingHashes.size} existing hashes, ${uniqueArticles.length} new unique articles`);

if (uniqueArticles.length === 0) {
  return [{ json: { _empty: true, message: 'All articles already exist in the sheet. No new articles to add.' } }];
}

return uniqueArticles;

// Log Results
// Summarizes the workflow execution results for monitoring.

const items = $input.all();
const count = items.length;
const now = new Date().toISOString();

console.log(`[${now}] AI Newsletter Collection Complete: ${count} new articles appended to Google Sheets.`);

return [{
  json: {
    status: 'success',
    articles_added: count,
    completed_at: now,
    message: `Successfully added ${count} new article(s) to the newsletter collection.`
  }
}];

// No New Articles Log
// This branch executes when all collected articles already exist in Google Sheets.

const now = new Date().toISOString();
console.log(`[${now}] AI Newsletter Collection: No new articles found. All items already in sheet.`);

return [{
  json: {
    status: 'no_new_articles',
    articles_added: 0,
    completed_at: now,
    message: 'No new articles to add. All collected items already exist in the sheet.'
  }
}];

// No Articles Collected Log
// This branch executes when the RSS feeds returned no usable articles.
// This could indicate feed URL changes or network issues.

const now = new Date().toISOString();
console.log(`[${now}] WARNING: AI Newsletter Collection found 0 articles from all feeds. Check feed URLs and network connectivity.`);

return [{
  json: {
    status: 'warning_no_articles',
    articles_added: 0,
    completed_at: now,
    message: 'WARNING: No articles collected from any feed. Verify RSS feed URLs are still valid and that the n8n instance has network access.'
  }
}];
